mapper.insert:
INSERT INTO openplatform_v2_subscription_t (
    id, app_id, permission_id, status, channel_type, channel_address, auth_type,
    approved_at, approved_by, create_time, last_update_time, create_by, last_update_by
) VALUES (
    #{id}, #{appId}, #{permissionId}, #{status}, #{channelType}, #{channelAddress}, #{authType},
    #{approvedAt}, #{approvedBy}, #{createTime}, #{lastUpdateTime}, #{createBy}, #{lastUpdateBy}
)
ON DUPLICATE KEY UPDATE id = id

INSERT INTO openplatform_v2_approval_record_t (
    id, combined_nodes, business_type, business_id, applicant_id, applicant_name,
    status, current_node, create_time, last_update_time, completed_at
) VALUES (
    #{id}, #{combinedNodes}, #{businessType}, #{businessId}, #{applicantId}, #{applicantName},
    #{status}, #{currentNode}, #{createTime}, #{lastUpdateTime}, #{completedAt}
)
ON DUPLICATE KEY UPDATE id = id

INSERT INTO openplatform_v2_approval_log_t (
    id, record_id, node_index, level, operator_id, operator_name, action, comment, create_time
) VALUES (
    #{id}, #{recordId}, #{nodeIndex}, #{level}, #{operatorId}, #{operatorName}, #{action}, #{comment}, #{createTime}
)
ON DUPLICATE KEY UPDATE id = id

INSERT INTO openplatform_app_permission_t (
    id, app_id, permission_id, tenant_id, permission_type, status,
    create_by, create_time, last_update_by, last_update_time
) VALUES (
    #{id}, #{appId}, #{permissionId}, #{tenantId}, #{permissionType}, #{status},
    #{createBy}, #{createTime}, #{lastUpdateBy}, #{lastUpdateTime}
)
ON DUPLICATE KEY UPDATE id = id

INSERT INTO openplatform_eflow_t (
    eflow_id, eflow_type, eflow_status, eflow_submit_user, eflow_submit_message,
    eflow_audit_user, eflow_audit_message, resource_type, resource_id,
    resource_info, resource_delta, tenant_id, status, create_by, create_time
) VALUES (
    #{eflowId}, #{eflowType}, #{eflowStatus}, #{eflowSubmitUser}, #{eflowSubmitMessage},
    #{eflowAuditUser}, #{eflowAuditMessage}, #{resourceType}, #{resourceId},
    #{resourceInfo}, #{resourceDelta}, #{tenantId}, #{status}, #{createBy}, #{createTime}
)
ON DUPLICATE KEY UPDATE eflow_id = eflow_id

INSERT INTO openplatform_eflow_log_t (
    eflow_log_id, eflow_log_trace_id, eflow_log_type, eflow_log_user,
    eflow_log_message, status, create_by, create_time
) VALUES (
    #{eflowLogId}, #{eflowLogTraceId}, #{eflowLogType}, #{eflowLogUser},
    #{eflowLogMessage}, #{status}, #{createBy}, #{createTime}
)
ON DUPLICATE KEY UPDATE eflow_log_id = eflow_log_id

